-- ----------------------------
-- Table structure for points_config
-- ----------------------------
DROP TABLE IF EXISTS `points_config`;
CREATE TABLE `points_config`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `first_chat_cost` int NULL DEFAULT 0,
  `repeat_chat_cost` int NULL DEFAULT 0,
  `message_cost` int NULL DEFAULT 0,
  `question_reward` int NULL DEFAULT 5,
  `answer_reward` int NULL DEFAULT 2,
  `first_contact_reward` int NULL DEFAULT 10,
  `repeat_contact_reward` int NULL DEFAULT 2,
  `reply_reward` int NULL DEFAULT 1,
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

